urlset:
{{ range site.Pages }}
  {{ if and (eq .Kind "term") (eq .Data.Plural "tags") }}
    {{ continue }}
  {{ end }}
  {{ if eq .Kind "taxonomy" }}
    {{ continue }}
  {{ end }}

    {{ .Permalink }}
    {{ if not .Lastmod.IsZero }}{{ .Lastmod.Format "2006-01-02T15:04:05-07:00" | safeHTML }}{{ end }}

{{ end }}
